package be.schaubroeck.lpb.rkm.rekenmotor.util;

import be.schaubroeck.lpb.corehr.util.web.instellingen.HrLoonafwerkingConfigDTO;
import be.schaubroeck.lpb.payrollhr.dto.LoonafwerkingConfigBO;
import be.schaubroeck.lpb.tools.HrLoonafwerkingConfig;

public class LoonafwerkingConfigMapper {
    public static LoonafwerkingConfigBO map(HrLoonafwerkingConfigDTO dto) {
        if (dto == null) {
            return null;
        }
        return LoonafwerkingConfigBO.builder()
                .adminId(dto.getAdminId())
                .sbnummer(getNullSafeBoolean(dto.getSbnummer()))
                .toepassingLoonbestanden(getNullSafeBoolean(dto.getToepassingLoonbestanden()))
                .csv(getNullSafeBoolean(dto.getCsv()))
                .txt(getNullSafeBoolean(dto.getTxt()))
                .downloadLinkBetaling(getNullSafeBoolean(dto.getDownloadLinkBetaling()))
                .hvzAfwijkendeVerwerking(getNullSafeBoolean(dto.getHvzAfwijkendeVerwerking()))
                .geenLegeLijnen(getNullSafeBoolean(dto.getGeenLegeLijnen()))
                .csvSeparator(dto.getCsvSeparator())
                .build();
    }
    public static LoonafwerkingConfigBO map(HrLoonafwerkingConfig configuratie) {
        if (configuratie == null) {
            return null;
        }
        return LoonafwerkingConfigBO.builder()
                .adminId(configuratie.getHrAdminCluster().getAdmin().getId())
                .sbnummer(getNullSafeBoolean(configuratie.getSlice().getSbnummer()))
                .toepassingLoonbestanden(getNullSafeBoolean(configuratie.getSlice().getToepassingLoonbestanden()))
                .csv(getNullSafeBoolean(configuratie.getSlice().getCsv()))
                .txt(getNullSafeBoolean(configuratie.getSlice().getTxt()))
                .downloadLinkBetaling(getNullSafeBoolean(configuratie.getSlice().getDownloadLinkBetaling()))
                .hvzAfwijkendeVerwerking(getNullSafeBoolean(configuratie.getSlice().getHvzAfwijkendeVerwerking()))
                .geenLegeLijnen(getNullSafeBoolean(configuratie.getSlice().getGeenLegeLijnen()))
                .csvSeparator(configuratie.getSlice().getCsvSeparator())
                .build();
    }

    public static boolean getNullSafeBoolean(Boolean value) {
        return value != null && value;
    }
}
